import React, { useEffect, useState } from 'react'
import PlaceAttributes from "../assets/PlaceAttributes.json";
import Meteorologgical_Images from "../assets/Meteorologgical_Images.json"
import { useSelectedFeatureContext } from '../contexts/SelectedFeatureContext';
import { useLoaderContext } from '../contexts/LoaderContext';

const MeteorologicalPage = () => {
    const { handleDistrictSelect,handleTehsilSelect, selectedDistrict,selectedTehsil,tehsilList  } = useSelectedFeatureContext();
    const [selectedImage, setSelectedImage] = useState(null);
    const { setIsLoading } = useLoaderContext();




    useEffect(() => {
        if (selectedTehsil && selectedTehsil !=='') {

          let item = Meteorologgical_Images.find((item) => item.TEHSIL === selectedTehsil);
          setSelectedImage(item);

         
        }
      }, [selectedTehsil]);


    return (
        <div className='dasboard_page_container'>

            <div className='main_dashboard'>
                <div className='left_panel'>

                <div className="left_panel_container">
                    <div className=' border-secondary p-2 mb-2'>

                        <label className=''>Select district</label>
                        <select className="form-select mb-3"
                            value={selectedDistrict ? selectedDistrict : ''}
                            onChange={handleDistrictSelect}>
                            <option value="">Select</option>
                            {[...new Set(PlaceAttributes.map((item) => item.DISTRICT))].map((item, index) =>
                                <option key={index} value={item}>{item}</option>
                            )}
                        </select>



                        <label className='mt-3'>Select taluka</label>
                        <select className="form-select mb-2"
                            value={selectedTehsil ? selectedTehsil : ''}
                            disabled={tehsilList && tehsilList.length === 0}
                            onChange={handleTehsilSelect} >
                            <option value="">Select</option>
                            {[...new Set(tehsilList && tehsilList.map((item) => item.TEHSIL))].map((item, index) =>
                                <option key={index} value={item}>{item}</option>
                            )}
                        </select>

                    </div>
</div>

                </div>

                <div className='right_panel'>
                <div className='right_panel_container'>
                    {selectedImage ? (
                        <>
                            <img src={selectedImage.url} alt='Meteorological Conditions' />
                            <div className="para_content">

                        
                                    <h1>Departure/Anomaly: </h1>
                                    <p> Difference between the current rainfall/temperature and the average (or normal) rainfall/temperature for a specific period and location. This metric is used to assess whether a region is experiencing above-average or below-average rainfall/temperature.
                                        </p>


                                    
                                    <h1>Legend</h1>
                                    <div className='item_table_container'>
                                        <table className='item_table'>
                                            <thead>
                                                <tr>
                                                    <th>Temperature Condition</th>
                                                    <th>Rainfall Remark</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                <tr>
                                                    <td><span style={{ color: "red" }}> Temperature Anomaly &gt; 2 (High temperature)</span></td>
                                                    <td><span style={{ color: "blue" }}> Departure &gt; 0 (Surplus)</span></td>
                                                </tr>
                                                <tr>
                                                    <td><span style={{ color: "blue" }}> Temperature Anomaly &lt; -2 (Low temperature)</span></td>
                                                    <td><span style={{ color: "red" }}> Departure &lt; 0 (Deficit)</span></td>
                                                </tr>
                                                <tr>
                                                    <td><span style={{ color: "green" }}> -2 &lt;= Temperature Anomaly &lt;= 2 (Normal temperature)</span></td>
                                                    <td>
                                                        Very Light to Light Rainfall (0.1 - 15.5 mm) <br />
                                                        Moderate Rainfall (15.6 - 64.4 mm) <br />
                                                        Heavy Rainfall (64.5 - 115.5 mm) <br />
                                                        Very Heavy Rainfall (115.6 - 204.4 mm) <br />
                                                        Extremely Heavy Rainfall (&ge; 204.5 mm)
                                                    </td>
                                                </tr>
                                            </tbody>
                                        </table>
                                    </div>

                                
                            </div>


                        </>

                    ) : (
                        <p>
                            Please select location.
                        </p>
                    )}

</div>
                </div>

            </div>
        </div>
    )
}

export default MeteorologicalPage